import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig({
  plugins: [react()],
  define: {
    // Mapping process.env to ensure compatibility with libraries expecting it
    'process.env': process.env
  },
  build: {
    outDir: 'dist',
    sourcemap: true,
    rollupOptions: {
