  }
});

export const generateId = () => {
    try {
        if (typeof crypto !== 'undefined' && crypto.randomUUID) {
            return crypto.randomUUID();
        }
    } catch (e) {}
    return Math.random().toString(36).substring(2, 15) + Date.now().toString(36);
};

export const getData = <T,>(key: string): T[] => {
    try {
        const data = localStorage.getItem(key);
        if (!data) return [];
        const parsed = JSON.parse(data);
        return Array.isArray(parsed) ? parsed : [];
    } catch (error) {
        return [];
    }
};

export const saveData = <T,>(key: string, data: T[]): boolean => {
    try {
        const timestamp = new Date().toISOString();
        const dataWithMeta = data.map(item => {
            if (item && typeof item === 'object') {
                const typed = item as any;
                let stableId = typed.id;
                if (key === 'users') stableId = typed.email || typed.username || typed.id;
                if (key === 'projects') stableId = typed.projectCode || typed.id;
                if (key === 'clients') stableId = typed.name || typed.id;

                return {
                    ...item,
                    id: stableId || generateId(),
                    updatedAt: typed.updatedAt || timestamp
                };
            }
            return item;
        });
        localStorage.setItem(key, JSON.stringify(dataWithMeta));

        // Background push - non-blocking
        const meta = getSystemMeta();
        if (meta.driveAccessToken && navigator.onLine) {
            pushToCloud().catch(() => {});
        }

        return true;
    } catch (error) {
        return false;
    }
};

export const getSystemLogo = (): string | null => localStorage.getItem('system_logo');
export const saveSystemLogo = (base64Data: string | null): void => {
    if (base64Data) localStorage.setItem('system_logo', base64Data);
    else localStorage.removeItem('system_logo');
};

export interface SystemMeta {
    id: string;
    versionLabel: string;
    lastCloudSync?: string;
    syncApiKey: string; 
    autoSync: boolean;
    backupLocation?: string;
    driveFileId?: string;
    driveAccessToken?: string;
    googleClientId?: string; // The user's specific GCP Client ID
}

// Default Client ID used as fallback
const DEFAULT_CLIENT_ID = '674092109435-96p21r75k1jgr7t1f0l4eohf5c49k23t.apps.googleusercontent.com';

export const getSystemMeta = (): SystemMeta => {
    const raw = localStorage.getItem('system_meta');

    // Priority: 1. Environment Var, 2. Default hardcoded
    const envClientId = (process.env as any).VITE_GOOGLE_CLIENT_ID;

    const defaultMeta: SystemMeta = { 
        id: 'meta', 
        versionLabel: 'v4.5 Google Cloud', 
        syncApiKey: '',
        autoSync: true,
        backupLocation: 'Google_Drive_AEWorks',
        googleClientId: envClientId || DEFAULT_CLIENT_ID
    };

    if (!raw) return defaultMeta;

    try {
        const data = JSON.parse(raw);
        const meta = Array.isArray(data) ? data[0] : data;
        // Merge stored meta with defaults, but ensure googleClientId isn't lost
        return { ...defaultMeta, ...meta };
    } catch {
        return defaultMeta;
    }
};

export const updateSystemMeta = (meta: Partial<SystemMeta>): void => {
    const current = getSystemMeta();
    localStorage.setItem('system_meta', JSON.stringify([{ ...current, ...meta }]));
};

export const DB_KEYS = ['clients', 'contacts', 'centres', 'framingMaterials', 'finishMaterials', 'projects', 'users', 'payrollRuns', 'defaultCostingVariables'];
const MASTER_FILE_NAME = "AEWORKS_MASTER_VAULT.json";

const getDriveHeaders = (token: string) => ({
    'Authorization': `Bearer ${token}`,
    'Content-Type': 'application/json'
});

/**
 * Enhanced Google Drive Sync: Robust file discovery across shared drives
 */
export const syncWithCloud = async (providedToken?: string): Promise<{success: boolean, message: string}> => {
    const meta = getSystemMeta();
    const token = providedToken || meta.driveAccessToken;

    if (!token) return { success: false, message: "Drive Authorization Required." };

    try {
        // Search including all drives and shared items
        const query = encodeURIComponent(`name='${MASTER_FILE_NAME}' and trashed=false`);
        const searchRes = await fetch(`https://www.googleapis.com/drive/v3/files?q=${query}&spaces=drive&supportsAllDrives=true&includeItemsFromAllDrives=true&fields=files(id, name, modifiedTime)`, {
            headers: getDriveHeaders(token)
        });

        if (!searchRes.ok) {
            if (searchRes.status === 401) {
                updateSystemMeta({ driveAccessToken: undefined });
                return { success: false, message: "Auth Session Expired. Please reconnect." };
            }
            throw new Error(`Drive Error: ${searchRes.status}`);
        }

        const searchData = await searchRes.json();
        let fileId = searchData.files?.[0]?.id;

        if (!fileId) {
            // Check if we are trying to initialize for the first time
            if (providedToken) {
                return { success: true, message: "Connected. Initializing first-time vault..." };
            }
            return { success: false, message: "Master Vault file not found on Drive." };
        }

        // Download content using 'alt=media'
        const fileRes = await fetch(`https://www.googleapis.com/drive/v3/files/${fileId}?alt=media`, {
            headers: getDriveHeaders(token)
        });

        if (!fileRes.ok) throw new Error("File Download Failed.");

        const actualData = await fileRes.json();

        // Atomic merge with prioritization of newer data
        DB_KEYS.forEach(key => {
            const local = getData<any>(key);
            const remote = actualData[key] || [];
            const merged = mergeDatasets(key, local, remote);
            localStorage.setItem(key, JSON.stringify(merged));
        });

        if (actualData._branding?.logo) saveSystemLogo(actualData._branding.logo);

        updateSystemMeta({ 
            driveFileId: fileId, 
            driveAccessToken: token,
            lastCloudSync: new Date().toISOString() 
        });

        return { success: true, message: "Cloud Sync Successful." };
    } catch (err) {
        console.error("Sync Failure:", err);
        return { success: false, message: "Drive link interrupted. Check network or permissions." };
    }
};

/**
 * Background Persistence to Google Drive
 */
export const pushToCloud = async () => {
    const meta = getSystemMeta();
    const token = meta.driveAccessToken;
    if (!token || !navigator.onLine) return;

    try {
        const fullDB: any = {
            _branding: { logo: getSystemLogo() },
            _meta: { ...meta, lastPush: new Date().toISOString() }
        };
        DB_KEYS.forEach(key => fullDB[key] = getData(key));

        let fileId = meta.driveFileId;

        // Verify/Find fileId if missing
        if (!fileId) {
            const query = encodeURIComponent(`name='${MASTER_FILE_NAME}' and trashed=false`);
            const searchRes = await fetch(`https://www.googleapis.com/drive/v3/files?q=${query}&supportsAllDrives=true&includeItemsFromAllDrives=true`, {
                headers: getDriveHeaders(token)
            });
            const searchData = await searchRes.json();
            fileId = searchData.files?.[0]?.id;
        }

        if (!fileId) {
            // Create new Master Vault if not found
            const metadata = { name: MASTER_FILE_NAME, mimeType: 'application/json' };
            const createRes = await fetch('https://www.googleapis.com/drive/v3/files', {
                method: 'POST',
                headers: getDriveHeaders(token),
                body: JSON.stringify(metadata)
            });
            const createData = await createRes.json();
            fileId = createData.id;
            updateSystemMeta({ driveFileId: fileId });
        }

        // Upload media content via PATCH
        await fetch(`https://www.googleapis.com/upload/drive/v3/files/${fileId}?uploadType=media`, {
            method: 'PATCH',
            headers: getDriveHeaders(token),
            body: JSON.stringify(fullDB)
        });

        console.log("Vault Update Committed to Drive.");
    } catch (err) {
        console.warn("Deferred: Drive write pending.");
    }
};

const mergeDatasets = (dbKey: string, local: any[], remote: any[]) => {
    const map = new Map();
    const getStableId = (item: any) => {
        if (dbKey === 'users') return item.email || item.username || item.id;
        if (dbKey === 'projects') return item.projectCode || item.id;
        if (dbKey === 'clients') return item.name || item.id;
        return item.id;
    };

    remote.forEach(remoteItem => {
        const id = getStableId(remoteItem);
        if (id) map.set(id, remoteItem);
    });

    local.forEach(localItem => {
        const id = getStableId(localItem);
        if (!id) return;
        const remoteItem = map.get(id);
        if (!remoteItem || new Date(localItem.updatedAt || 0) > new Date(remoteItem.updatedAt || 0)) {
            map.set(id, localItem);
        }
    });

    return Array.from(map.values());
};

import React, { useState, useEffect } from 'react';
import { User, AuthUser } from '../../types';
import Button from '../ui/Button';
import Icon from '../ui/Icon';
import { useAppContext } from '../../hooks/useAppContext';
import * as db from '../../services/db';

interface LoginModalProps {
    onLogin: (user: User) => void;
}

const LoginModal: React.FC<LoginModalProps> = ({ onLogin }) => {
    const [identifier, setIdentifier] = useState('');
    const [password, setPassword] = useState('');
    const [activeTab, setActiveTab] = useState<'login' | 'setup'>('login');
    const [isLoading, setIsLoading] = useState(false);
    const [showInstructions, setShowInstructions] = useState(false);
    const [logo, setLogo] = useState<string | null>(db.getSystemLogo());
    const [config, setConfig] = useState(db.getSystemMeta());
    const { showNotification } = useAppContext();

    const currentOrigin = window.location.origin;

    useEffect(() => {
        const localUsers = db.getData('users');
        const meta = db.getSystemMeta();
        if (localUsers.length <= 1 && !meta.driveAccessToken) {
            setActiveTab('setup');
        }
    }, []);

    const handleLogin = () => {
        const users = db.getData<AuthUser>('users');
        const cleanId = identifier.trim().toLowerCase();
        const cleanPw = password.trim();

        if (!cleanId || !cleanPw) {
            showNotification('Enter ID and Access Token.', 'warning');
            return;
        }

        const foundUser = users.find(u => 
            (u.email?.toLowerCase() === cleanId || u.username?.toLowerCase() === cleanId) && 
            u.password === cleanPw
        );

        if (foundUser) {
            const updatedUsers = users.map(u => u.id === foundUser.id ? { ...u, lastLogin: new Date().toISOString() } : u);
            db.saveData('users', updatedUsers);
            onLogin({ username: foundUser.username, email: foundUser.email, role: foundUser.role });
            showNotification(`Access Authorized.`, 'success');
        } else {
            showNotification('Identity Check Failed. Sync with Drive if using a new device.', 'error');
        }
    };

    const handleClientIdChange = (val: string) => {
        const cleanVal = val.trim();
        setConfig(prev => ({ ...prev, googleClientId: cleanVal }));
        db.updateSystemMeta({ googleClientId: cleanVal });
    };

    const handleResetConfig = () => {
        if (confirm("Reset to factory Client ID? This will clear your custom Google connection settings.")) {
            localStorage.removeItem('system_meta');
            const freshMeta = db.getSystemMeta();
            setConfig(freshMeta);
            showNotification("Configuration Reset.");
        }
    };

    const copyOrigin = () => {
        navigator.clipboard.writeText(currentOrigin);
        showNotification("Origin URL copied to clipboard!");
    };

    const handleGoogleDriveSync = () => {
        if (!config.googleClientId) {
            showNotification("Please enter a Google Client ID.", "warning");
            return;
        }

        setIsLoading(true);
        try {
            if (!(window as any).google?.accounts?.oauth2) {
                showNotification("Loading Google Auth...", "warning");
                setIsLoading(false);
                return;
            }

            const client = (window as any).google.accounts.oauth2.initTokenClient({
                client_id: config.googleClientId,
                scope: 'https://www.googleapis.com/auth/drive.file',
                callback: async (response: any) => {
                    if (response.error) {
                        console.error("OAuth Error:", response);
                        setIsLoading(false);
                        if (response.error === 'popup_closed_by_user') {
                            showNotification("Login window closed.", "warning");
                        } else {
                            showNotification(`Google Error: ${response.error}`, "error");
                        }
                        return;
                    }

                    const result = await db.syncWithCloud(response.access_token);
                    setIsLoading(false);

                    if (result.success) {
                        showNotification('Master Vault Bonded.', 'success');
                        setActiveTab('login');
                        setLogo(db.getSystemLogo());
                    } else {
                        showNotification(result.message, 'warning');
                    }
                },
                error_callback: (err: any) => {
                    console.error("GIS Error:", err);
                    setIsLoading(false);
                    showNotification("Blocked: Check 'Test Users' in Google Console.", "error");
                }
            });
            client.requestAccessToken();
        } catch (e) {
            showNotification("Auth System Offline.", "error");
            setIsLoading(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-slate-950 flex justify-center items-center z-50 p-4 overflow-y-auto">
            <div className="absolute inset-0 opacity-10 bg-[radial-gradient(circle_at_center,_#3b82f6_0%,_transparent_70%)] pointer-events-none"></div>

            <div className="bg-white rounded-[2.5rem] w-full max-w-sm overflow-hidden shadow-2xl relative border border-slate-100 animate-fade-in my-auto">
                <div className="flex border-b border-slate-100 bg-slate-50/50">
                    <button onClick={() => setActiveTab('login')} className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'login' ? 'bg-white text-blue-600 border-b-2 border-blue-600' : 'text-slate-400 hover:text-slate-600'}`}>
                        <Icon name="fas fa-user-shield" className="mr-2" /> Identity
                    </button>
                    <button onClick={() => setActiveTab('setup')} className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'setup' ? 'bg-white text-blue-600 border-b-2 border-blue-600' : 'text-slate-400 hover:text-slate-600'}`}>
                        <Icon name="fab fa-google-drive" className="mr-2" /> Cloud Bridge
                    </button>
                </div>

                <div className="p-8 text-center">
                    <div className="mb-6 flex justify-center">
                        <div className="w-20 h-20 bg-slate-900 rounded-[1.5rem] flex items-center justify-center text-white border-4 border-slate-50 overflow-hidden p-2 shadow-xl">
                            {logo ? <img src={logo} alt="Logo" className="max-h-full max-w-full object-contain" /> : <Icon name="fas fa-industry" className="text-3xl text-blue-500" />}
                        </div>
                    </div>

                    {activeTab === 'login' ? (
                        <div className="space-y-4 animate-fade-in">
                            <div className="mb-6">
                                <h3 className="text-xl font-black text-slate-900 uppercase tracking-tighter leading-none">Portal Login</h3>
                                <p className="text-[9px] text-slate-400 uppercase tracking-widest mt-1">Personnel Access Only</p>
                            </div>
                            <div className="relative">
                                <Icon name="fas fa-user" className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 text-xs" />
                                <input type="text" placeholder="STAFF ID / EMAIL" value={identifier} onChange={(e) => setIdentifier(e.target.value)} className="w-full pl-12 pr-5 py-4 border border-slate-200 rounded-2xl text-[11px] font-black placeholder:text-slate-300 focus:border-blue-500 bg-slate-50 outline-none transition-all" />
                            </div>
                            <div className="relative">
                                <Icon name="fas fa-key" className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 text-xs" />
                                <input type="password" placeholder="ACCESS TOKEN" value={password} onChange={(e) => setPassword(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && handleLogin()} className="w-full pl-12 pr-5 py-4 border border-slate-200 rounded-2xl text-[11px] font-black placeholder:text-slate-300 focus:border-blue-500 bg-slate-50 outline-none transition-all" />
                            </div>
                            <Button onClick={handleLogin} variant="primary" size="lg" className="w-full py-4 text-[10px] tracking-[0.2em] uppercase font-black rounded-2xl shadow-xl shadow-blue-600/20">Unlock System</Button>
                        </div>
                    ) : (
                        <div className="space-y-5 animate-fade-in text-left">
                            <div className="mb-4 text-center">
                                <h3 className="text-xl font-black text-slate-900 uppercase tracking-tighter leading-none">Cloud Bridge</h3>
                                <p className="text-[9px] text-slate-400 uppercase tracking-widest mt-1">Configure Remote Sync</p>
                            </div>

                            <div className="p-4 bg-blue-50 border border-blue-100 rounded-2xl mb-2">
                                <h4 className="text-[9px] font-black text-blue-900 uppercase tracking-tight mb-2 flex items-center justify-between">
                                    <span>Authorized Origin</span>
                                    <button onClick={copyOrigin} className="text-blue-600 hover:text-blue-800"><Icon name="fas fa-copy" /></button>
                                </h4>
                                <code className="block text-[10px] font-mono font-bold text-blue-700 break-all bg-white p-2 rounded-lg border border-blue-200">
                                    {currentOrigin}
                                </code>
                                <p className="text-[8px] text-blue-600 mt-2 font-bold uppercase leading-tight italic">
                                    * Copy this into "Authorized JavaScript Origins" in GCP Console.
                                </p>
                            </div>

                            <div className="p-4 bg-red-50 border border-red-100 rounded-2xl">
                                <h4 className="text-[9px] font-black text-red-900 uppercase tracking-tight mb-1 flex items-center gap-2">
                                    <Icon name="fas fa-user-lock" /> Fixing "Access Blocked"
                                </h4>
                                <p className="text-[9px] text-red-700 leading-tight font-bold">
                                    If you see "Access Blocked", your email is not a "Test User". 
                                    <button onClick={() => setShowInstructions(!showInstructions)} className="ml-1 text-red-900 underline font-black">Fix It Now</button>
                                </p>
                            </div>

                            {showInstructions && (
                                <div className="p-4 bg-slate-900 text-white rounded-2xl text-[9px] font-bold space-y-3 animate-fade-in border border-slate-800">
                                    <div className="space-y-1">
                                        <p className="text-blue-400 uppercase font-black">Google Console Requirements:</p>
                                        <ol className="list-decimal list-inside space-y-1 opacity-90">
                                            <li>Go to **OAuth Consent Screen** in GCP</li>
                                            <li>Under **Test Users**, click **Add Users**</li>
                                            <li>Enter your Gmail and Save</li>
                                            <li>Ensure **Publishing Status** is "Testing"</li>
                                        </ol>
                                    </div>
                                    <button onClick={handleResetConfig} className="w-full py-2 bg-slate-800 text-slate-400 rounded-lg hover:text-white border border-slate-700 uppercase tracking-widest text-[8px] font-black">Reset To Defaults</button>
                                </div>
                            )}

                            <div>
                                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1 mb-1 block">Google Client ID</label>
                                <textarea value={config.googleClientId} onChange={(e) => handleClientIdChange(e.target.value)} rows={2} className="w-full p-3 border border-slate-200 rounded-xl text-[9px] font-mono font-bold bg-slate-50 outline-none focus:border-blue-500" placeholder="Enter Client ID from GCP" />
                            </div>

                            <Button onClick={handleGoogleDriveSync} variant="success" size="lg" disabled={isLoading} icon={isLoading ? "fas fa-sync animate-spin" : "fab fa-google"} className="w-full py-4 text-[10px] tracking-[0.2em] uppercase font-black rounded-2xl shadow-xl shadow-green-600/20 bg-slate-900 border-none">
                                {isLoading ? 'Verifying...' : 'Authorize Drive Bridge'}
                            </Button>
                        </div>
                    )}
                </div>
            </div>

            <div className="fixed bottom-6 text-center w-full pointer-events-none">
                <p className="text-[9px] font-black text-slate-600 uppercase tracking-[0.5em] opacity-30">AEWorks v4.5 Enterprise Bridge</p>
            </div>
        </div>
    );
};

export default LoginModal;

import React, { useState, useRef, useEffect } from 'react';
import Button from '../ui/Button';
import Icon from '../ui/Icon';
import { View, Project } from '../../types';
import ProjectListModal from './ProjectListModal';
import { useProjectContext } from '../../hooks/useProjectContext';
import { useAppContext } from '../../hooks/useAppContext';
import * as db from '../../services/db';

interface ToolbarProps {
    setView: (view: View) => void;
}

const Toolbar: React.FC<ToolbarProps> = ({ setView }) => {
    const { 
        currentProject, projects, setProjects, setCurrentProject, resetProject,
        setClients, setContacts, setCentres, setFramingMaterials, setFinishMaterials,
        updateProject
    } = useProjectContext();

    const { currentUser, showNotification } = useAppContext();
    const [isProjectListOpen, setIsProjectListOpen] = useState(false);
    const [isDbMenuOpen, setIsDbMenuOpen] = useState(false);
    const [isSyncing, setIsSyncing] = useState(false);
    const [lastSyncTime, setLastSyncTime] = useState<string | null>(db.getSystemMeta().lastCloudSync || null);

    const dbMenuRef = useRef<HTMLDivElement>(null);

    const isAdmin = currentUser?.role === 'admin';
    const isViewer = currentUser?.role === 'viewer';

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (dbMenuRef.current && !dbMenuRef.current.contains(event.target as Node)) {
                setIsDbMenuOpen(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const handleManualSync = async () => {
        const meta = db.getSystemMeta();
        if (!meta.driveAccessToken) {
            showNotification("Authorization required. Re-link via Login screen.", "warning");
            return;
        }
        setIsSyncing(true);
        const result = await db.syncWithCloud();
        setIsSyncing(false);
        if (result.success) {
            showNotification(result.message, "success");
            const newMeta = db.getSystemMeta();
            setLastSyncTime(newMeta.lastCloudSync || null);

            // Refresh local state to reflect synced data
            setProjects(db.getData('projects'));
            setClients(db.getData('clients'));
            setContacts(db.getData('contacts'));
            setCentres(db.getData('centres'));
            setFramingMaterials(db.getData('framingMaterials'));
            setFinishMaterials(db.getData('finishMaterials'));
        } else {
            showNotification(result.message, "warning");
        }
    };

    const handleSaveProject = () => {
        if (isViewer) return;
        if (!currentProject.projectCode) {
            showNotification('Project Code Required.', 'error');
            return;
        }
        updateProject({ ...currentProject, updatedAt: new Date().toISOString() });
        showNotification(`Project State Persistent.`);
    };

    const handleLoadProject = (projectCode: string) => {
        const projectToLoad = projects.find(p => p.projectCode === projectCode);
        if (projectToLoad) {
            setCurrentProject(projectToLoad);
            setIsProjectListOpen(false);
        }
    };

    const ManageButton = ({ onClick, icon, label, colorClass }: any) => (
        <button 
            onClick={() => { onClick(); setIsDbMenuOpen(false); }} 
            className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 transition-colors border-b border-slate-50 last:border-0 font-bold"
        >
            <Icon name={icon} className={`${colorClass} w-4 text-center`}/> {label}
        </button>
    );

    const isCloudActive = !!db.getSystemMeta().driveAccessToken;

    return (
        <>
