                            <div>
                                <div className="flex justify-between items-center mb-1 ml-1">
                                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Google Client ID</label>
                                    <button onClick={copySetupLink} className="text-[8px] font-black text-blue-600 uppercase hover:underline">
                                        <Icon name="fas fa-link" className="mr-1" /> Copy Setup Link
                                    </button>
                                </div>
                                <textarea value={config.googleClientId} onChange={(e) => handleClientIdChange(e.target.value)} rows={2} className="w-full p-3 border border-slate-200 rounded-xl text-[9px] font-mono font-bold bg-slate-50 outline-none focus:border-blue-500" placeholder="Enter Client ID from GCP" />
                            </div>

                            <Button onClick={handleGoogleDriveSync} variant="success" size="lg" disabled={isLoading} icon={isLoading ? "fas fa-sync animate-spin" : "fab fa-google"} className="w-full py-4 text-[10px] tracking-[0.2em] uppercase font-black rounded-2xl shadow-xl shadow-green-600/20 bg-slate-900 border-none">
                                {isLoading ? 'Verifying...' : 'Authorize Drive Bridge'}
                            </Button>

                            <button onClick={handleResetConfig} className="w-full text-center text-[8px] font-black text-slate-300 uppercase hover:text-red-400 transition-colors py-2 tracking-widest">Reset Identity Config</button>
                        </div>
                    )}
                </div>
            </div>

            <div className="fixed bottom-6 text-center w-full pointer-events-none">
                <p className="text-[9px] font-black text-slate-600 uppercase tracking-[0.5em] opacity-30">AEWorks v4.5 Enterprise Bridge</p>
            </div>
        </div>
    );
};

export default LoginModal;

export const generateId = () => {
    try {
        if (typeof crypto !== 'undefined' && crypto.randomUUID) {
            return crypto.randomUUID();
        }
    } catch (e) {}
    return Math.random().toString(36).substring(2, 15) + Date.now().toString(36);
};

export const getData = <T,>(key: string): T[] => {
    try {
        const data = localStorage.getItem(key);
        if (!data) return [];
        const parsed = JSON.parse(data);
        return Array.isArray(parsed) ? parsed : [];
    } catch (error) {
        return [];
    }
};

export const saveData = <T,>(key: string, data: T[]): boolean => {
    try {
        const timestamp = new Date().toISOString();
        const dataWithMeta = data.map(item => {
            if (item && typeof item === 'object') {
                const typed = item as any;
                let stableId = typed.id;
                if (key === 'users') stableId = typed.email || typed.username || typed.id;
                if (key === 'projects') stableId = typed.projectCode || typed.id;
                if (key === 'clients') stableId = typed.name || typed.id;

                return {
                    ...item,
                    id: stableId || generateId(),
                    updatedAt: typed.updatedAt || timestamp
                };
            }
            return item;
        });
        localStorage.setItem(key, JSON.stringify(dataWithMeta));
        return true;
    } catch (error) {
        return false;
    }
};

export const getSystemLogo = (): string | null => localStorage.getItem('system_logo');
export const saveSystemLogo = (base64Data: string | null): void => {
    if (base64Data) localStorage.setItem('system_logo', base64Data);
    else localStorage.removeItem('system_logo');
};

export interface SystemMeta {
    id: string;
    versionLabel: string;
    lastCloudSync?: string;
    syncApiKey: string; 
    autoSync: boolean;
    backupLocation?: string;
    driveFileId?: string;
    driveAccessToken?: string;
    googleClientId?: string; 
    connectedEmail?: string;
    driveFileUrl?: string;
}

const DEFAULT_CLIENT_ID = '674092109435-96p21r75k1jgr7t1f0l4eohf5c49k23t.apps.googleusercontent.com';

export const getSystemMeta = (): SystemMeta => {
    const raw = localStorage.getItem('system_meta');

    // Check URL for auto-config (cid = Client ID)
    const urlParams = new URLSearchParams(window.location.search);
    const urlClientId = urlParams.get('cid');

    const defaultMeta: SystemMeta = { 
        id: 'meta', 
        versionLabel: 'v4.5 Google Cloud', 
        syncApiKey: '',
        autoSync: true,
        backupLocation: 'Google_Drive_AEWorks',
        googleClientId: urlClientId || DEFAULT_CLIENT_ID
    };

    // If URL has a client ID, update local storage immediately to persist for this device
    if (urlClientId) {
        let existing: any = {};
        if (raw) {
            try {
                const parsed = JSON.parse(raw);
                existing = Array.isArray(parsed) ? parsed[0] : parsed;
            } catch (e) {}
        }
        localStorage.setItem('system_meta', JSON.stringify([{ ...defaultMeta, ...existing, googleClientId: urlClientId }]));

        // Clean URL after ingestion to keep it tidy
        const newUrl = window.location.pathname;
        window.history.replaceState({}, '', newUrl);
        return { ...defaultMeta, ...existing, googleClientId: urlClientId };
    }

    if (!raw) return defaultMeta;

    try {
        const data = JSON.parse(raw);
        const meta = Array.isArray(data) ? data[0] : data;
        return { ...defaultMeta, ...meta };
    } catch {
        return defaultMeta;
    }
};

export const updateSystemMeta = (meta: Partial<SystemMeta>): void => {
    const current = getSystemMeta();
    localStorage.setItem('system_meta', JSON.stringify([{ ...current, ...meta }]));
};

export const DB_KEYS = ['clients', 'contacts', 'centres', 'framingMaterials', 'finishMaterials', 'projects', 'users', 'payrollRuns', 'defaultCostingVariables'];
const MASTER_FILE_NAME = "AEWORKS_MASTER_VAULT.json";

const getDriveHeaders = (token: string) => ({
    'Authorization': `Bearer ${token}`,
    'Content-Type': 'application/json'
});

export const syncWithCloud = async (providedToken?: string): Promise<{success: boolean, message: string}> => {
    const meta = getSystemMeta();
    const token = providedToken || meta.driveAccessToken;

    if (!token) return { success: false, message: "Drive Authorization Required." };

    try {
        // Identify the user for the UI
        let email = meta.connectedEmail;
        try {
            const userRes = await fetch('https://www.googleapis.com/oauth2/v3/userinfo', { headers: getDriveHeaders(token) });
            if (userRes.ok) {
                const userData = await userRes.json();
                email = userData.email;
            }
        } catch (e) {}

        const query = encodeURIComponent(`name='${MASTER_FILE_NAME}' and trashed=false`);
        const searchRes = await fetch(`https://www.googleapis.com/drive/v3/files?q=${query}&spaces=drive&fields=files(id, name, modifiedTime, webViewLink)`, {
            headers: getDriveHeaders(token)
        });

        if (!searchRes.ok) {
            if (searchRes.status === 401) {
                updateSystemMeta({ driveAccessToken: undefined, connectedEmail: undefined });
                return { success: false, message: "Auth Session Expired. Re-authorize." };
            }
            throw new Error(`Drive Error: ${searchRes.status}`);
        }

        const searchData = await searchRes.json();
        let fileId = searchData.files?.[0]?.id;
        let fileUrl = searchData.files?.[0]?.webViewLink;

        if (!fileId) {
            updateSystemMeta({ driveAccessToken: token, connectedEmail: email });
            const pushResult = await pushToCloud();
            if (pushResult.success) {
                return { success: true, message: `Vault Initialized on Drive (${email})` };
            }
            return { success: true, message: `Connected as ${email}. Click 'Commit' to push data.` };
        }

        const fileRes = await fetch(`https://www.googleapis.com/drive/v3/files/${fileId}?alt=media`, {
            headers: getDriveHeaders(token)
        });

        if (!fileRes.ok) throw new Error("Vault Download Failed.");

        const actualData = await fileRes.json();

        DB_KEYS.forEach(key => {
            const local = getData<any>(key);
            const remote = actualData[key] || [];
            const merged = mergeDatasets(key, local, remote);
            localStorage.setItem(key, JSON.stringify(merged));
        });

        if (actualData._branding?.logo) saveSystemLogo(actualData._branding.logo);

        updateSystemMeta({ 
            driveFileId: fileId, 
            driveAccessToken: token,
            driveFileUrl: fileUrl,
            connectedEmail: email,
            lastCloudSync: new Date().toISOString() 
        });

        return { success: true, message: `Synced with ${email}` };
    } catch (err) {
        console.error("Sync Failure:", err);
        return { success: false, message: "Sync Failed: Cloud Unreachable." };
    }
};

export const pushToCloud = async (): Promise<{success: boolean, message: string}> => {
    const meta = getSystemMeta();
    const token = meta.driveAccessToken;
    if (!token) return { success: false, message: "No active Drive link." };
    if (!navigator.onLine) return { success: false, message: "Device is offline." };

    try {
        const fullDB: any = {
            _branding: { logo: getSystemLogo() },
            _meta: { ...meta, lastPush: new Date().toISOString() }
        };
        DB_KEYS.forEach(key => fullDB[key] = getData(key));

        let fileId = meta.driveFileId;
        let fileUrl = meta.driveFileUrl;

        if (!fileId) {
            const query = encodeURIComponent(`name='${MASTER_FILE_NAME}' and trashed=false`);
            const searchRes = await fetch(`https://www.googleapis.com/drive/v3/files?q=${query}&fields=files(id, webViewLink)`, {
                headers: getDriveHeaders(token)
            });
            const searchData = await searchRes.json();
            fileId = searchData.files?.[0]?.id;
            fileUrl = searchData.files?.[0]?.webViewLink;
        }

        if (!fileId) {
            const metadata = { name: MASTER_FILE_NAME, mimeType: 'application/json' };
            const createRes = await fetch('https://www.googleapis.com/drive/v3/files?fields=id,webViewLink', {
                method: 'POST',
                headers: getDriveHeaders(token),
                body: JSON.stringify(metadata)
            });
            if (!createRes.ok) throw new Error("Could not create vault file.");
            const createData = await createRes.json();
            fileId = createData.id;
            fileUrl = createData.webViewLink;
            updateSystemMeta({ driveFileId: fileId, driveFileUrl: fileUrl });
        }

        const uploadRes = await fetch(`https://www.googleapis.com/upload/drive/v3/files/${fileId}?uploadType=media`, {
            method: 'PATCH',
            headers: getDriveHeaders(token),
            body: JSON.stringify(fullDB)
        });

        if (!uploadRes.ok) {
            if (uploadRes.status === 401) {
                updateSystemMeta({ driveAccessToken: undefined });
                return { success: false, message: "Session Expired." };
            }
            throw new Error(`Upload Failed: ${uploadRes.status}`);
        }

        updateSystemMeta({ lastCloudSync: new Date().toISOString(), driveFileUrl: fileUrl });
        return { success: true, message: "Synced to Drive." };
    } catch (err: any) {
        return { success: false, message: err.message || "Write Error." };
    }
};

const mergeDatasets = (dbKey: string, local: any[], remote: any[]) => {
    const map = new Map();
    const getStableId = (item: any) => {
        if (dbKey === 'users') return item.email || item.username || item.id;
        if (dbKey === 'projects') return item.projectCode || item.id;
        if (dbKey === 'clients') return item.name || item.id;
        return item.id;
    };
    remote.forEach(remoteItem => {
        const id = getStableId(remoteItem);
        if (id) map.set(id, remoteItem);
    });
    local.forEach(localItem => {
        const id = getStableId(localItem);
        if (!id) return;
        const remoteItem = map.get(id);
        if (!remoteItem || new Date(localItem.updatedAt || 0) > new Date(remoteItem.updatedAt || 0)) {
            map.set(id, localItem);
        }
    });
    return Array.from(map.values());
};

import React, { useState, useRef, useEffect } from 'react';
import Button from '../ui/Button';
import Icon from '../ui/Icon';
import { View, Project } from '../../types';
import ProjectListModal from './ProjectListModal';
import { useProjectContext } from '../../hooks/useProjectContext';
import { useAppContext } from '../../hooks/useAppContext';
import * as db from '../../services/db';

interface ToolbarProps {
    setView: (view: View) => void;
}

const Toolbar: React.FC<ToolbarProps> = ({ setView }) => {
    const { 
        currentProject, projects, setProjects, setCurrentProject, resetProject,
        setClients, setContacts, setCentres, setFramingMaterials, setFinishMaterials,
        updateProject
    } = useProjectContext();

    const { currentUser, showNotification } = useAppContext();
    const [isProjectListOpen, setIsProjectListOpen] = useState(false);
    const [isDbMenuOpen, setIsDbMenuOpen] = useState(false);
    const [isSyncing, setIsSyncing] = useState(false);
    const [isCommitting, setIsCommitting] = useState(false);
    const [syncError, setSyncError] = useState(false);
    const [systemMeta, setSystemMeta] = useState(db.getSystemMeta());

    const dbMenuRef = useRef<HTMLDivElement>(null);

    const isAdmin = currentUser?.role === 'admin';
    const isViewer = currentUser?.role === 'viewer';

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (dbMenuRef.current && !dbMenuRef.current.contains(event.target as Node)) {
                setIsDbMenuOpen(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const refreshAppState = () => {
        setProjects(db.getData('projects'));
        setClients(db.getData('clients'));
        setContacts(db.getData('contacts'));
        setCentres(db.getData('centres'));
        setFramingMaterials(db.getData('framingMaterials'));
        setFinishMaterials(db.getData('finishMaterials'));
        setSystemMeta(db.getSystemMeta());
    };

    const handleGoogleAuth = () => {
        const config = db.getSystemMeta();
        if (!config.googleClientId) {
            showNotification("Missing Google Client ID configuration.", "error");
            return;
        }

        setIsSyncing(true);
        try {
            const client = (window as any).google.accounts.oauth2.initTokenClient({
                client_id: config.googleClientId,
                scope: 'https://www.googleapis.com/auth/drive.file https://www.googleapis.com/auth/userinfo.email',
                callback: async (response: any) => {
                    if (response.error) {
                        setIsSyncing(false);
                        showNotification(`Google Error: ${response.error}`, "error");
                        return;
                    }
                    const result = await db.syncWithCloud(response.access_token);
                    setIsSyncing(false);
                    if (result.success) {
                        showNotification(result.message, 'success');
                        refreshAppState();
                    } else {
                        showNotification(result.message, 'warning');
                    }
                }
            });
            client.requestAccessToken();
        } catch (e) {
            setIsSyncing(false);
            showNotification("Auth System Offline.", "error");
        }
    };

    const handleManualSync = async () => {
        if (!systemMeta.driveAccessToken) {
            handleGoogleAuth();
            return;
        }
        setIsSyncing(true);
        setSyncError(false);
        const result = await db.syncWithCloud();
        setIsSyncing(false);
        if (result.success) {
            showNotification(result.message, "success");
            refreshAppState();
        } else {
            setSyncError(true);
            showNotification(result.message, "warning");
        }
    };

    const handleSaveProject = async () => {
        if (isViewer) return;
        if (!currentProject.projName || currentProject.projName.trim() === '') {
            showNotification('Project Name Required.', 'error');
            return;
        }
        if (!currentProject.projectCode) {
            showNotification('Generating Code...', 'warning');
            return;
        }

        setIsCommitting(true);
        updateProject({ ...currentProject, updatedAt: new Date().toISOString() });

        const meta = db.getSystemMeta();
        if (meta.driveAccessToken) {
            const cloudResult = await db.pushToCloud();
            if (cloudResult.success) {
                showNotification(`Synced to Drive Account: ${meta.connectedEmail}`, 'success');
            } else {
                showNotification(`Saved Locally. Drive Sync: ${cloudResult.message}`, 'warning');
                setSyncError(true);
            }
            setSystemMeta(db.getSystemMeta());
        } else {
            showNotification(`Offline Save. Link Cloud Bridge for centralization.`, 'warning');
        }
        setIsCommitting(false);
    };

    const handleLoadProject = (projectCode: string) => {
        const projectToLoad = projects.find(p => p.projectCode === projectCode);
        if (projectToLoad) {
            setCurrentProject(projectToLoad);
            setIsProjectListOpen(false);
        }
    };

    const isCloudActive = !!systemMeta.driveAccessToken;
    const driveFileUrl = systemMeta.driveFileUrl || (systemMeta.driveFileId ? `https://drive.google.com/file/d/${systemMeta.driveFileId}/view` : null);

    let badgeClass = 'bg-slate-50 border-slate-200 text-slate-400 hover:bg-slate-100 hover:text-slate-600 shadow-inner';
    let dotClass = 'bg-slate-300';

    if (isSyncing || isCommitting) {
        badgeClass = 'bg-blue-50 border-blue-200 text-blue-600 animate-pulse shadow-md';
        dotClass = 'bg-blue-500 animate-ping';
    } else if (syncError) {
        badgeClass = 'bg-red-50 border-red-200 text-red-600 hover:bg-red-100 shadow-md';
        dotClass = 'bg-red-500 shadow-[0_0_5px_#ef4444]';
    } else if (isCloudActive) {
        badgeClass = 'bg-white border-green-200 text-green-700 hover:border-green-400 shadow-sm';
        dotClass = 'bg-green-500 shadow-[0_0_5px_#10b981]';
    }

    return (
        <>
            <div className="flex flex-row md:flex-wrap gap-1.5 mb-2 bg-white p-1.5 rounded-xl shadow-sm justify-start md:justify-between items-center relative z-[40] border border-slate-200">
                <div className="flex flex-row flex-nowrap gap-1.5 items-center flex-grow overflow-x-auto no-scrollbar">
                    {!isViewer && (
                        <Button onClick={handleSaveProject} variant="primary" icon={isCommitting ? "fas fa-sync animate-spin" : "fas fa-save"} disabled={isCommitting} size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">
                            {isCommitting ? 'Pushing...' : 'Commit'}
                        </Button>
                    )}
                    <Button onClick={() => setIsProjectListOpen(true)} variant="success" icon="fas fa-folder-open" size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">Load</Button>
                    {!isViewer && <Button onClick={resetProject} variant="warning" icon="fas fa-file" size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">New</Button>}
                    <div className="hidden md:block w-px bg-slate-200 mx-1 h-5 flex-shrink-0"></div>
                    <Button onClick={() => setView(View.TRACKER)} variant="primary" icon="fas fa-columns" size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">Tracker</Button>
                </div>

                <div className="flex items-center gap-3">
                    <div className="flex flex-col items-end">
                        <div className="flex items-center gap-1">
                            <button onClick={handleManualSync} disabled={isSyncing || isCommitting} className={`flex items-center gap-2 px-3 py-1.5 rounded-lg border text-[10px] font-black uppercase tracking-widest transition-all ${badgeClass}`}>
                                <div className={`w-1.5 h-1.5 rounded-full ${dotClass}`}></div>
                                <span className="hidden sm:inline">
                                    {isSyncing ? 'Syncing...' : syncError ? 'Re-link' : isCloudActive ? (systemMeta.connectedEmail ? `Linked: ${systemMeta.connectedEmail}` : 'Sync Cloud') : 'Connect Cloud'}
                                </span>
                            </button>
                            {driveFileUrl && (
                                <a href={driveFileUrl} target="_blank" rel="noopener noreferrer" className="p-1.5 text-slate-400 hover:text-blue-600 transition-colors" title="Locate Master Vault on Google Drive">
                                    <Icon name="fas fa-external-link-alt" className="text-[10px]" />
                                </a>
                            )}
                        </div>
                        {systemMeta.lastCloudSync && isCloudActive && !syncError && (
                            <span className="text-[8px] font-bold text-slate-400 uppercase tracking-tighter mt-1">
                                Latest Sync: {new Date(systemMeta.lastCloudSync).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                            </span>
                        )}
                    </div>

                    {!isViewer && (
                        <div className="relative" ref={dbMenuRef}>
                            <button onClick={() => setIsDbMenuOpen(!isDbMenuOpen)} className={`flex items-center gap-1.5 px-3 py-1.5 text-[10px] font-black uppercase tracking-widest rounded-lg border transition-all ${isDbMenuOpen ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-700 border-slate-300'}`}>
                                <Icon name="fas fa-database" />
                            </button>
                            {isDbMenuOpen && (
                                <div className="absolute top-[calc(100%+4px)] right-0 w-64 bg-white rounded-xl shadow-2xl border border-slate-200 py-1 z-[100] animate-fade-in origin-top-right">
                                    <div className="px-3 py-2 text-[9px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 mb-1">Repositories</div>
                                    <button onClick={() => { setView(View.MANAGE_CLIENTS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold border-b border-slate-50"><Icon name="fas fa-building" className="text-indigo-600 w-4"/> Clients</button>
                                    <button onClick={() => { setView(View.MANAGE_CONTACTS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold border-b border-slate-50"><Icon name="fas fa-address-card" className="text-teal-600 w-4"/> Personnel</button>
                                    <button onClick={() => { setView(View.MANAGE_MATERIALS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold border-b border-slate-50"><Icon name="fas fa-boxes" className="text-rose-600 w-4"/> Materials</button>
                                    {isAdmin && (
                                        <>
                                            <div className="px-3 py-2 text-[9px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 mt-1 mb-1">Control</div>
                                            <button onClick={() => { setView(View.MANAGE_USERS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold"><Icon name="fas fa-user-shield" className="text-blue-700 w-4"/> Access Keys</button>
                                        </>
                                    )}
                                </div>
                            )}
                        </div>
                    )}
                </div>
            </div>
            <ProjectListModal isOpen={isProjectListOpen} onClose={() => setIsProjectListOpen(false)} onLoadProject={handleLoadProject} projects={projects} />
        </>
    );
};

export default Toolbar;

import React, { useState, useEffect } from 'react';
import { User, AuthUser } from '../../types';
import Button from '../ui/Button';
import Icon from '../ui/Icon';
import { useAppContext } from '../../hooks/useAppContext';
import * as db from '../../services/db';

interface LoginModalProps {
    onLogin: (user: User) => void;
}

const LoginModal: React.FC<LoginModalProps> = ({ onLogin }) => {
    const [identifier, setIdentifier] = useState('');
    const [password, setPassword] = useState('');
    const [activeTab, setActiveTab] = useState<'login' | 'setup'>('login');
    const [isLoading, setIsLoading] = useState(false);
    const [showInstructions, setShowInstructions] = useState(false);
    const [logo, setLogo] = useState<string | null>(db.getSystemLogo());
    const [config, setConfig] = useState(db.getSystemMeta());
    const { showNotification } = useAppContext();

    const currentOrigin = window.location.origin;

    useEffect(() => {
        const localUsers = db.getData('users');
        const meta = db.getSystemMeta();
        if (localUsers.length <= 1 && !meta.driveAccessToken) {
            setActiveTab('setup');
        }
        // Refresh local config state from DB
        setConfig(db.getSystemMeta());
    }, []);

    const handleLogin = () => {
        const users = db.getData<AuthUser>('users');
        const cleanId = identifier.trim().toLowerCase();
        const cleanPw = password.trim();

        if (!cleanId || !cleanPw) {
            showNotification('Enter ID and Access Token.', 'warning');
            return;
        }

        const foundUser = users.find(u => 
            (u.email?.toLowerCase() === cleanId || u.username?.toLowerCase() === cleanId) && 
            u.password === cleanPw
        );

        if (foundUser) {
            const updatedUsers = users.map(u => u.id === foundUser.id ? { ...u, lastLogin: new Date().toISOString() } : u);
            db.saveData('users', updatedUsers);
            onLogin({ username: foundUser.username, email: foundUser.email, role: foundUser.role });
            showNotification(`Access Authorized.`, 'success');
        } else {
            showNotification('Identity Check Failed. Sync with Drive if using a new device.', 'error');
        }
    };

    const handleClientIdChange = (val: string) => {
        const cleanVal = val.trim();
        setConfig(prev => ({ ...prev, googleClientId: cleanVal }));
        db.updateSystemMeta({ googleClientId: cleanVal });
    };

    const handleResetConfig = () => {
        if (confirm("Reset to factory Client ID? This will clear your custom Google connection settings.")) {
            localStorage.removeItem('system_meta');
            const freshMeta = db.getSystemMeta();
            setConfig(freshMeta);
            showNotification("Configuration Reset.");
        }
    };

    const copyOrigin = () => {
        navigator.clipboard.writeText(currentOrigin);
        showNotification("Origin URL copied to clipboard!");
    };

    const copySetupLink = () => {
        if (!config.googleClientId) {
            showNotification("Configure a Client ID first.", "warning");
            return;
        }
        // Creates a URL that auto-configures the app on a new device
        const setupUrl = `${window.location.origin}${window.location.pathname}?cid=${encodeURIComponent(config.googleClientId)}`;
        navigator.clipboard.writeText(setupUrl);
        showNotification("Multi-device setup link copied!", "success");
    };

    const handleGoogleDriveSync = () => {
        if (!config.googleClientId) {
            showNotification("Please enter a Google Client ID.", "warning");
            return;
        }

        setIsLoading(true);
        try {
            if (!(window as any).google?.accounts?.oauth2) {
                showNotification("Loading Google Auth...", "warning");
                setIsLoading(false);
                return;
            }

            const client = (window as any).google.accounts.oauth2.initTokenClient({
                client_id: config.googleClientId,
                scope: 'https://www.googleapis.com/auth/drive.file https://www.googleapis.com/auth/userinfo.email',
                callback: async (response: any) => {
                    if (response.error) {
                        console.error("OAuth Error:", response);
                        setIsLoading(false);
                        if (response.error === 'popup_closed_by_user') {
                            showNotification("Login window closed.", "warning");
                        } else {
                            showNotification(`Google Error: ${response.error}`, "error");
                        }
                        return;
                    }

                    const result = await db.syncWithCloud(response.access_token);
                    setIsLoading(false);

                    if (result.success) {
                        showNotification(result.message, 'success');
                        setActiveTab('login');
                        setLogo(db.getSystemLogo());
                    } else {
                        showNotification(result.message, 'warning');
                    }
                },
                error_callback: (err: any) => {
                    console.error("GIS Error:", err);
                    setIsLoading(false);
                    setShowInstructions(true);
                    showNotification("Blocked: Please check the 'Test Users' guide below.", "error");
                }
            });
            client.requestAccessToken();
        } catch (e) {
            showNotification("Auth System Offline.", "error");
            setIsLoading(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-slate-950 flex justify-center items-center z-50 p-4 overflow-y-auto">
            <div className="absolute inset-0 opacity-10 bg-[radial-gradient(circle_at_center,_#3b82f6_0%,_transparent_70%)] pointer-events-none"></div>

            <div className="bg-white rounded-[2.5rem] w-full max-w-sm overflow-hidden shadow-2xl relative border border-slate-100 animate-fade-in my-auto">
                <div className="flex border-b border-slate-100 bg-slate-50/50">
                    <button onClick={() => setActiveTab('login')} className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'login' ? 'bg-white text-blue-600 border-b-2 border-blue-600' : 'text-slate-400 hover:text-slate-600'}`}>
                        <Icon name="fas fa-user-shield" className="mr-2" /> Identity
                    </button>
                    <button onClick={() => setActiveTab('setup')} className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'setup' ? 'bg-white text-blue-600 border-b-2 border-blue-600' : 'text-slate-400 hover:text-slate-600'}`}>
                        <Icon name="fab fa-google-drive" className="mr-2" /> Cloud Bridge
                    </button>
                </div>

                <div className="p-8 text-center">
                    <div className="mb-6 flex justify-center">
                        <div className="w-20 h-20 bg-slate-900 rounded-[1.5rem] flex items-center justify-center text-white border-4 border-slate-50 overflow-hidden p-2 shadow-xl">
                            {logo ? <img src={logo} alt="Logo" className="max-h-full max-w-full object-contain" /> : <Icon name="fas fa-industry" className="text-3xl text-blue-500" />}
                        </div>
                    </div>

                    {activeTab === 'login' ? (
                        <div className="space-y-4 animate-fade-in">
                            <div className="mb-6">
                                <h3 className="text-xl font-black text-slate-900 uppercase tracking-tighter leading-none">Portal Login</h3>
                                <p className="text-[9px] text-slate-400 uppercase tracking-widest mt-1">Personnel Access Only</p>
                            </div>
                            <div className="relative">
                                <Icon name="fas fa-user" className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 text-xs" />
                                <input type="text" placeholder="STAFF ID / EMAIL" value={identifier} onChange={(e) => setIdentifier(e.target.value)} className="w-full pl-12 pr-5 py-4 border border-slate-200 rounded-2xl text-[11px] font-black placeholder:text-slate-300 focus:border-blue-500 bg-slate-50 outline-none transition-all" />
                            </div>
                            <div className="relative">
                                <Icon name="fas fa-key" className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 text-xs" />
                                <input type="password" placeholder="ACCESS TOKEN" value={password} onChange={(e) => setPassword(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && handleLogin()} className="w-full pl-12 pr-5 py-4 border border-slate-200 rounded-2xl text-[11px] font-black placeholder:text-slate-300 focus:border-blue-500 bg-slate-50 outline-none transition-all" />
                            </div>
                            <Button onClick={handleLogin} variant="primary" size="lg" className="w-full py-4 text-[10px] tracking-[0.2em] uppercase font-black rounded-2xl shadow-xl shadow-blue-600/20">Unlock System</Button>
                        </div>
                    ) : (
                        <div className="space-y-5 animate-fade-in text-left">
                            <div className="mb-4 text-center">
                                <h3 className="text-xl font-black text-slate-900 uppercase tracking-tighter leading-none">Cloud Bridge</h3>
                                <p className="text-[9px] text-slate-400 uppercase tracking-widest mt-1">Centralized Sync Hub</p>
                            </div>

                            <div className="p-4 bg-blue-50 border border-blue-100 rounded-2xl mb-2 text-[10px] leading-relaxed text-blue-800">
                                <p className="font-bold mb-1 uppercase tracking-tight"><Icon name="fas fa-info-circle"/> How Sync Works</p>
                                The Google Account you link below acts as the <strong>Central Server</strong>. Link all devices to the SAME Google Account to see the same projects.
                            </div>

                            <div className="p-4 bg-slate-50 border border-slate-200 rounded-2xl mb-2">
                                <h4 className="text-[9px] font-black text-slate-900 uppercase tracking-tight mb-2 flex items-center justify-between">
                                    <span>Authorized Origin</span>
                                    <button onClick={copyOrigin} className="text-blue-600 hover:text-blue-800"><Icon name="fas fa-copy" /></button>
                                </h4>
                                <code className="block text-[10px] font-mono font-bold text-slate-700 break-all bg-white p-2 rounded-lg border border-slate-200">
                                    {currentOrigin}
                                </code>
                            </div>

                            <div>
                                <div className="flex justify-between items-center mb-1 ml-1">
                                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Google Client ID</label>
                                    <button onClick={copySetupLink} className="text-[8px] font-black text-blue-600 uppercase hover:underline">
                                        <Icon name="fas fa-link" className="mr-1" /> Copy Setup Link
                                    </button>
                                </div>
                                <textarea value={config.googleClientId} onChange={(e) => handleClientIdChange(e.target.value)} rows={2} className="w-full p-3 border border-slate-200 rounded-xl text-[9px] font-mono font-bold bg-slate-50 outline-none focus:border-blue-500" placeholder="Enter Client ID from GCP" />
                            </div>

                            <Button onClick={handleGoogleDriveSync} variant="success" size="lg" disabled={isLoading} icon={isLoading ? "fas fa-sync animate-spin" : "fab fa-google"} className="w-full py-4 text-[10px] tracking-[0.2em] uppercase font-black rounded-2xl shadow-xl shadow-green-600/20 bg-slate-900 border-none">
                                {isLoading ? 'Linking Account...' : 'Link Central Google Drive'}
                            </Button>

                            <button onClick={handleResetConfig} className="w-full text-center text-[8px] font-black text-slate-300 uppercase hover:text-red-400 transition-colors py-2 tracking-widest">Reset Identity Config</button>
                        </div>
                    )}
                </div>
            </div>

            <div className="fixed bottom-6 text-center w-full pointer-events-none">
                <p className="text-[9px] font-black text-slate-600 uppercase tracking-[0.5em] opacity-30">AEWorks v4.5 Enterprise Bridge</p>
            </div>
        </div>
    );
};

export default LoginModal;

import React, { useState, useEffect } from 'react';
import ManagePage from './ManagePage';
import CrudTable, { Column } from './CrudTable';
import { AuthUser } from '../../types';
import * as db from '../../services/db';
import { useAppContext } from '../../hooks/useAppContext';
import Icon from '../ui/Icon';
import Button from '../ui/Button';
import Modal from '../ui/Modal';

interface ManageUsersPageProps {
    goBack: () => void;
}

const ManageUsersPage: React.FC<ManageUsersPageProps> = ({ goBack }) => {
    const { currentUser, showNotification } = useAppContext();
    const [users, setUsers] = useState<AuthUser[]>([]);
    const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
    const [systemMeta] = useState(db.getSystemMeta());

    // New User State
    const [newUser, setNewUser] = useState<Partial<AuthUser>>({
        username: '',
        email: '',
        password: '',
        role: 'viewer'
    });

    useEffect(() => {
        setUsers(db.getData<AuthUser>('users'));
    }, []);

    const columns: Column<AuthUser>[] = [
        { key: 'username', label: 'Login ID', type: 'text' },
        { key: 'email', label: 'Primary Email', type: 'text' },
        { 
            key: 'role', 
            label: 'Tier / Level', 
            type: 'select',
            options: [
                { label: 'Level 1: Super Admin', value: 'admin' },
                { label: 'Level 2: Manager', value: 'manager' },
                { label: 'Level 3: Viewer', value: 'viewer' }
            ],
            render: (val) => {
                const colors: any = { admin: 'text-blue-600', manager: 'text-purple-600', viewer: 'text-slate-500' };
                const labels: any = { admin: 'L1: Admin', manager: 'L2: Manager', viewer: 'L3: Viewer' };
                return <span className={`font-black uppercase tracking-tighter text-[10px] ${colors[val] || ''}`}>{labels[val] || val}</span>;
            }
        },
        { 
            key: 'password', 
            label: 'Access Token', 
            type: 'text',
            render: (val) => <span className="font-mono text-slate-300 select-none tracking-widest">••••••••</span>
        },
        { 
            key: 'lastLogin', 
            label: 'Recent Access',
            render: (val) => val ? new Date(val).toLocaleDateString() : <span className="opacity-30 italic text-[9px]">Never</span>
        }
    ];

    const handleSaveList = (updatedUsers: AuthUser[]) => {
        const admins = updatedUsers.filter(u => u.role === 'admin');
        if (admins.length === 0) {
            showNotification('Security Error: At least one Super Admin required.', 'error');
            return;
        }

        if (db.saveData<AuthUser>('users', updatedUsers)) {
            setUsers(db.getData<AuthUser>('users'));
            showNotification('Access Registry Updated. Click "COMMIT" in Toolbar to sync with Drive.', 'success');
        }
    };

    const copyOnboardingLink = () => {
        const setupUrl = `${window.location.origin}${window.location.pathname}?cid=${encodeURIComponent(systemMeta.googleClientId || '')}`;
        navigator.clipboard.writeText(setupUrl);
        showNotification("Staff Onboarding Link copied!", "success");
    };

    const generateRandomToken = () => {
        const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
        let result = '';
        for (let i = 0; i < 8; i++) {
            result += chars.charAt(Math.floor(Math.random() * chars.length));
        }
        setNewUser(prev => ({ ...prev, password: result }));
    };

    const handleCreateUser = () => {
        if (!newUser.username || !newUser.password || !newUser.email) {
            showNotification('All fields are required for new account provisioning.', 'warning');
            return;
        }

        const newAccount: AuthUser = {
            id: db.generateId(),
            username: newUser.username,
            email: newUser.email,
            password: newUser.password,
            role: newUser.role as any,
            updatedAt: new Date().toISOString()
        };

        const updated = [newAccount, ...users];
        if (db.saveData('users', updated)) {
            setUsers(updated);
            setIsCreateModalOpen(false);
            setNewUser({ username: '', email: '', password: '', role: 'viewer' });
            showNotification(`Account created. Remember to "Commit" to push this user to Drive.`, 'success');
        }
    };

    if (currentUser?.role !== 'admin') {
        return (
            <ManagePage title="Security Violation" icon="fas fa-user-lock" goBack={goBack}>
                <div className="p-16 text-center bg-red-50 rounded-2xl border-2 border-red-100 flex flex-col items-center">
                    <div className="w-24 h-24 bg-red-100 rounded-full flex items-center justify-center mb-6 text-red-600 text-5xl">
                        <Icon name="fas fa-shield-virus" className="animate-pulse" />
                    </div>
                    <h3 className="text-3xl font-black text-red-900 mb-2 uppercase tracking-tighter">Access Restricted</h3>
                    <p className="text-red-700 max-w-md text-sm leading-relaxed">
                        Identity & Access Management (IAM) is reserved for Level 1 System Administrators. 
                    </p>
                    <Button onClick={goBack} variant="outline" className="mt-8 border-red-200 text-red-700 hover:bg-red-100">Return to Operations</Button>
                </div>
            </ManagePage>
        );
    }

    return (
        <ManagePage title="Access Key Management" icon="fas fa-user-shield" goBack={goBack}>
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-4 mb-8">
                <div className="lg:col-span-2 bg-slate-900 text-white p-6 rounded-2xl shadow-xl">
                    <h4 className="text-lg font-black flex items-center gap-3 mb-2 uppercase tracking-tighter">
                        <Icon name="fas fa-terminal" className="text-blue-400" />
                        Central User Registry
                    </h4>
                    <p className="text-slate-400 text-sm leading-relaxed mb-4">
                        Users defined here are shared across all devices linked to: <br/>
                        <strong className="text-blue-300">{systemMeta.connectedEmail || 'No Drive Linked Yet'}</strong>
                    </p>
                    <div className="flex gap-2">
                        <Button onClick={() => setIsCreateModalOpen(true)} variant="primary" icon="fas fa-user-plus" size="sm" className="px-5 shadow-lg shadow-blue-500/20">
                            Create User
                        </Button>
                        <Button onClick={copyOnboardingLink} variant="outline" icon="fas fa-link" size="sm" className="border-slate-700 text-slate-300 hover:bg-slate-800">
                            Staff Setup Link
                        </Button>
                    </div>
                </div>

                <div className="bg-blue-50 border border-blue-100 p-6 rounded-2xl">
                    <h5 className="text-[10px] font-black text-blue-900 uppercase tracking-widest mb-3">Sync Status</h5>
                    <div className="flex items-center gap-3">
                        <div className={`w-3 h-3 rounded-full ${systemMeta.driveAccessToken ? 'bg-green-500 animate-pulse' : 'bg-slate-300'}`}></div>
                        <span className="text-xs font-bold text-blue-800">
                            {systemMeta.driveAccessToken ? 'Cloud Bridge Active' : 'Disconnected from Drive'}
                        </span>
                    </div>
                    <p className="text-[10px] text-blue-600 mt-2 leading-tight">
                        After editing users, you MUST click <strong>COMMIT</strong> in the top toolbar to sync changes to other devices.
                    </p>
                </div>
            </div>

            <CrudTable<AuthUser>
                columns={columns}
                data={users}
                onSave={handleSaveList}
                newItemFactory={() => ({ id: db.generateId(), username: '', email: '', password: '', role: 'viewer' })}
                itemName="Access Key"
                hideAddButton={true}
            />

            <Modal isOpen={isCreateModalOpen} onClose={() => setIsCreateModalOpen(false)} title="Provision Account" titleIcon="fas fa-user-shield">
                <div className="space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="space-y-4">
                            <div>
                                <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1 ml-1">Login ID / Username</label>
                                <input type="text" className="w-full p-3 border border-slate-200 rounded-xl bg-slate-50 focus:bg-white outline-none font-bold" placeholder="e.g. G.Johnson" value={newUser.username} onChange={e => setNewUser({...newUser, username: e.target.value})} />
