        setProjects(db.getData<Project>('projects'));
    };

    const migrateProject = (p: any): Project => {
        if (!p.jobs || p.jobs.length === 0) {
            const migratedJob: Job = {
                id: db.generateId(),
                name: 'Primary Job',
                framingTakeOff: p.framingTakeOff || [],
                finishesTakeOff: p.finishesTakeOff || []
            };
            return {
                ...p,
                jobs: [migratedJob],
                framingTakeOff: undefined,
                finishesTakeOff: undefined
            };
        }
        return p;
    };

    useEffect(() => {
        const setup = async () => {
            refreshLocalState();

            const redirectView = localStorage.getItem('redirect_view');
            if (redirectView) {
                setView(View[redirectView as keyof typeof View] || View.DASHBOARD);
                localStorage.removeItem('redirect_view');
            }

            if (currentUser?.role === 'admin') {
                const users = db.getData<any>('users');
                const adminUser = users.find((u: any) => u.username === currentUser.username || u.email === currentUser.email);
                if (adminUser && adminUser.password === 'masterPassword123') {
                    setIsForcePasswordChangeOpen(true);
                }
            }

            const loadedDefaults = db.getData<CostingVariables>('defaultCostingVariables');
            let defaultVars: CostingVariables = {};
            if (loadedDefaults.length > 0) {
                defaultVars = loadedDefaults[0];
            } else {
                 Object.values(COST_VARS_STRUCTURE).forEach(category => {
                    Object.entries(category).forEach(([key, val]) => {
                        defaultVars[key] = val[1] as number;
                    });
                });
                db.saveData('defaultCostingVariables', [defaultVars]);
            }
            setDefaultCostingVariables(defaultVars);

            const autosaved = localStorage.getItem('autosave_current_project');
            if (autosaved) {
                try {
                    const p = JSON.parse(autosaved);
                    setCurrentProject(migrateProject(p));
                } catch (e) {
                    setCurrentProject(createInitialProject(defaultVars));
                }
            } else {
                setCurrentProject(createInitialProject(defaultVars));
            }
        };

        setup();
    }, [showNotification, currentUser]);

    // Centralized Project Code Generation
    useEffect(() => {
        if (currentProject.projName.trim() !== '') {
            const generatedCode = generateProjectCode(currentProject.projName, currentProject.jobsThisYear, currentProject.year);
            if (generatedCode !== currentProject.projectCode) {
                setCurrentProject(prev => ({ ...prev, projectCode: generatedCode }));
            }
        } else if (currentProject.projectCode !== '') {
            setCurrentProject(prev => ({ ...prev, projectCode: '' }));
        }
    }, [currentProject.projName, currentProject.jobsThisYear, currentProject.year]);

    useEffect(() => {
        if (autosaveTimerRef.current) {
            clearTimeout(autosaveTimerRef.current);
        }
        autosaveTimerRef.current = window.setTimeout(() => {
            if (currentProject.projName || currentProject.projectCode) {
                localStorage.setItem('autosave_current_project', JSON.stringify(currentProject));
            }
        }, 2000);

        return () => {
             if (autosaveTimerRef.current) clearTimeout(autosaveTimerRef.current);
        };
    }, [currentProject]);

    const updateProject = useCallback((project: Project, shouldSyncToMasterList = true) => {
        const migratedProject = migrateProject(project);

        if (migratedProject.projectCode === currentProject.projectCode) {
            setCurrentProject(migratedProject);
        }

        const existingProjects = db.getData<Project>('projects');
        const idx = existingProjects.findIndex(p => p.projectCode === migratedProject.projectCode);
        const updatedProjects = [...existingProjects];

        if (idx > -1) {
            updatedProjects[idx] = { ...migratedProject, updatedAt: new Date().toISOString() };
        } else if (shouldSyncToMasterList) {
            updatedProjects.push({ ...migratedProject, updatedAt: new Date().toISOString() });
        }

        db.saveData('projects', updatedProjects);
        setProjects(updatedProjects);

        // Handle Automated Contact/Client Logic
        if (migratedProject.clientName && migratedProject.clientName.trim() !== '') {
            const statusInt = parseInt(migratedProject.projectStatus || '0', 10);
            const currentClients = db.getData<Client>('clients');
            const currentContacts = db.getData<Contact>('contacts');

            const normalizedName = migratedProject.clientName.toLowerCase().trim();
            const clientExists = currentClients.some(c => c.name.toLowerCase().trim() === normalizedName);
            const contactExists = currentContacts.some(c => c.name.toLowerCase().trim() === normalizedName);

            if (statusInt >= 15) {
                // Should be a formal client
                if (!clientExists) {
                    const newClient: Client = {
                        id: db.generateId(),
                        name: migratedProject.clientName.trim(),
                        mgr: migratedProject.clientMgr || 'N/A',
                        phone: migratedProject.clientPhone || '',
                        email: migratedProject.clientEmail || '',
                        address: migratedProject.clientAddr || '',
                        destination: migratedProject.destCitySelect || '',
                        updatedAt: new Date().toISOString()
                    };
                    const updatedClients = [newClient, ...currentClients];
                    db.saveData('clients', updatedClients);
                    setClients(updatedClients);
                    showNotification(`Customer "${migratedProject.clientName}" promoted to Global Registry.`, 'success');

                    // Cleanup from contacts if it was a prospect
                    if (contactExists) {
                        const updatedContacts = currentContacts.filter(c => c.name.toLowerCase().trim() !== normalizedName);
                        db.saveData('contacts', updatedContacts);
                        setContacts(updatedContacts);
                    }
                }
            } else {
                // Not started, should be a prospect contact if not already a client
                if (!clientExists && !contactExists) {
                    const newContact: Contact = {
                        id: db.generateId(),
                        name: migratedProject.clientName.trim(),
                        designation: 'Potential Client',
                        category: 'Prospect',
                        phone1: migratedProject.clientPhone || '',
                        email1: migratedProject.clientEmail || '',
                        updatedAt: new Date().toISOString()
                    };
                    const updatedContacts = [newContact, ...currentContacts];
                    db.saveData('contacts', updatedContacts);
                    setContacts(updatedContacts);
                    showNotification(`New Prospect "${migratedProject.clientName}" indexed.`, 'success');
                }
            }
        }
    }, [currentProject.projectCode, showNotification]);

    const updateGlobalDefaults = useCallback((vars: CostingVariables) => {
        setDefaultCostingVariables(vars);
        db.saveData('defaultCostingVariables', [vars]);
    }, []);

    const handleSetStatus = (value: number) => {
        if (currentUser?.role === 'viewer') {
            showNotification("Access denied.", "error");
            return;
        }
        const updated = { ...currentProject, projectStatus: value.toString(), updatedAt: new Date().toISOString() };
        updateProject(updated);
    };

    const projectContextValue = useMemo(() => ({
        currentProject, setCurrentProject,
        clients, setClients,
        contacts, setContacts,
        centres, setCentres,
        framingMaterials, setFramingMaterials,
        finishMaterials, setFinishMaterials,
        projects, setProjects,
        defaultCostingVariables, setDefaultCostingVariables,
        updateProject,
        updateGlobalDefaults,
        resetProject: () => {
            const p = createInitialProject(defaultCostingVariables);
            setCurrentProject(p);
            localStorage.removeItem('autosave_current_project');
        },
    }), [currentProject, clients, contacts, centres, framingMaterials, finishMaterials, projects, defaultCostingVariables, updateProject, updateGlobalDefaults]);

    const renderView = () => {
        switch (view) {
            case View.DASHBOARD: return <TabContainer />;
            case View.MANAGE_CLIENTS: return <ManageClientsPage goBack={() => setView(View.DASHBOARD)} />;
            case View.MANAGE_CONTACTS: return <ManageContactsPage goBack={() => setView(View.DASHBOARD)} />;
            case View.MANAGE_CENTRES: return <ManageCentresPage goBack={() => setView(View.DASHBOARD)} />;
            case View.MANAGE_MATERIALS: return <ManageMaterialsPage goBack={() => setView(View.DASHBOARD)} />;
            case View.MANAGE_USERS: return <ManageUsersPage goBack={() => setView(View.DASHBOARD)} />;
            case View.TRACKER: return <ProjectTrackerBoard setView={setView} />;
            default: return <TabContainer />;
        }
    };

    const containerClass = view === View.TRACKER 
        ? "w-full px-2 h-[100dvh] flex flex-col" 
        : "max-w-7xl mx-auto p-1.5 md:p-2 h-[100dvh] flex flex-col";

    return (
        <ProjectContextProvider value={projectContextValue}>
            <div className={containerClass}>
                <div className="hidden md:block flex-shrink-0">
                    <div className="flex justify-between items-center mb-1">
                        {onBack && (
                            <Button onClick={onBack} variant="outline" size="sm" icon="fas fa-arrow-left" className="py-1 px-3 text-xs">Back</Button>
                        )}
                        <UserBar />
                    </div>
                    <Header />
                </div>

                <div className="md:hidden flex-shrink-0 bg-slate-900 text-white p-2 rounded-lg mb-1.5 flex justify-between items-center shadow-md">
                    <div className="flex items-center gap-2">
                        {onBack && (
                            <button onClick={onBack} className="bg-slate-700 p-2 rounded-full"><Icon name="fas fa-arrow-left" className="text-xs"/></button>
                        )}
                        <div className="flex flex-col">
                            <span className="font-black text-xs leading-tight">AEWorks</span>
                        </div>
                    </div>
                    <button 
                        onClick={() => setCurrentUser(null)} 
                        className="bg-red-600/20 text-red-500 p-2 rounded-full hover:bg-red-600 hover:text-white transition-all"
                        title="Logout"
                    >
                        <Icon name="fas fa-power-off" className="text-xs" />
                    </button>
                </div>

                {view !== View.TRACKER && (
                    <div className="flex-shrink-0">
                        <StatusBar statusValue={parseInt(currentProject.projectStatus, 10)} onSetStatus={handleSetStatus} />
                    </div>
                )}

                <div className="flex-shrink-0">
                    <Toolbar setView={setView} />
                </div>

                <main className="flex-grow overflow-hidden relative h-full">{renderView()}</main>

                <ForcePasswordChangeModal isOpen={isForcePasswordChangeOpen} onClose={() => setIsForcePasswordChangeOpen(false)} />
            </div>
        </ProjectContextProvider>
    );
};

export default MainLayout;

import React, { useState, useRef, useEffect } from 'react';
import Button from '../ui/Button';
import Icon from '../ui/Icon';
import { View, Project } from '../../types';
import ProjectListModal from './ProjectListModal';
import { useProjectContext } from '../../hooks/useProjectContext';
import { useAppContext } from '../../hooks/useAppContext';
import * as db from '../../services/db';

interface ToolbarProps {
    setView: (view: View) => void;
}

const Toolbar: React.FC<ToolbarProps> = ({ setView }) => {
    const { 
        currentProject, projects, setProjects, setCurrentProject, resetProject,
        setClients, setContacts, setCentres, setFramingMaterials, setFinishMaterials,
        updateProject
    } = useProjectContext();

    const { currentUser, setCurrentUser, showNotification } = useAppContext();
    const [isProjectListOpen, setIsProjectListOpen] = useState(false);
    const [isDbMenuOpen, setIsDbMenuOpen] = useState(false);
    const [isSyncing, setIsSyncing] = useState(false);
    const [isCommitting, setIsCommitting] = useState(false);
    const [syncError, setSyncError] = useState(false);
    const [systemMeta, setSystemMeta] = useState(db.getSystemMeta());

    const dbMenuRef = useRef<HTMLDivElement>(null);

    const isAdmin = currentUser?.role === 'admin';
    const isViewer = currentUser?.role === 'viewer';

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (dbMenuRef.current && !dbMenuRef.current.contains(event.target as Node)) {
                setIsDbMenuOpen(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const refreshAppState = () => {
        setProjects(db.getData('projects'));
        setClients(db.getData('clients'));
        setContacts(db.getData('contacts'));
        setCentres(db.getData('centres'));
        setFramingMaterials(db.getData('framingMaterials'));
        setFinishMaterials(db.getData('finishMaterials'));
        setSystemMeta(db.getSystemMeta());
    };

    const handleGoogleAuth = () => {
        const config = db.getSystemMeta();
        if (!config.googleClientId) {
            showNotification("Missing Google Client ID configuration.", "error");
            return;
        }

        setIsSyncing(true);
        try {
            const client = (window as any).google.accounts.oauth2.initTokenClient({
                client_id: config.googleClientId,
                scope: 'https://www.googleapis.com/auth/drive.file https://www.googleapis.com/auth/userinfo.email',
                callback: async (response: any) => {
                    if (response.error) {
                        setIsSyncing(false);
                        showNotification(`Google Error: ${response.error}`, "error");
                        return;
                    }
                    const result = await db.syncWithCloud(response.access_token);
                    setIsSyncing(false);
                    if (result.success) {
                        showNotification(result.message, 'success');
                        refreshAppState();
                    } else {
                        showNotification(result.message, 'warning');
                    }
                }
            });
            client.requestAccessToken();
        } catch (e) {
            setIsSyncing(false);
            showNotification("Auth System Offline.", "error");
        }
    };

    const handleManualSync = async () => {
        if (!systemMeta.driveAccessToken) {
            handleGoogleAuth();
            return;
        }
        setIsSyncing(true);
        setSyncError(false);
        const result = await db.syncWithCloud();
        setIsSyncing(false);
        if (result.success) {
            showNotification(result.message, "success");
            refreshAppState();
        } else {
            setSyncError(true);
            showNotification(result.message, "warning");
        }
    };

    const handleSaveProject = async () => {
        if (isViewer) return;
        if (!currentProject.projName || currentProject.projName.trim() === '') {
            showNotification('Project Name Required.', 'error');
            return;
        }
        if (!currentProject.projectCode) {
            showNotification('Generating Code...', 'warning');
            return;
        }

        setIsCommitting(true);
        updateProject({ ...currentProject, updatedAt: new Date().toISOString() });

        const meta = db.getSystemMeta();
        if (meta.driveAccessToken) {
            const cloudResult = await db.pushToCloud();
            if (cloudResult.success) {
                showNotification(`Synced to Drive Account: ${meta.connectedEmail}`, 'success');
            } else {
                showNotification(`Saved Locally. Drive Sync: ${cloudResult.message}`, 'warning');
                setSyncError(true);
            }
            setSystemMeta(db.getSystemMeta());
        } else {
            showNotification(`Offline Save. Link Cloud Bridge for centralization.`, 'warning');
        }
        setIsCommitting(false);
    };

    const handleLoadProject = (projectCode: string) => {
        const projectToLoad = projects.find(p => p.projectCode === projectCode);
        if (projectToLoad) {
            setCurrentProject(projectToLoad);
            setIsProjectListOpen(false);
        }
    };

    const handleLogout = () => {
        setCurrentUser(null);
    };

    const isCloudActive = !!systemMeta.driveAccessToken;
    const driveFileUrl = systemMeta.driveFileUrl || (systemMeta.driveFileId ? `https://drive.google.com/file/d/${systemMeta.driveFileId}/view` : null);

    let badgeClass = 'bg-slate-50 border-slate-200 text-slate-400 hover:bg-slate-100 hover:text-slate-600 shadow-inner';
    let dotClass = 'bg-slate-300';

    if (isSyncing || isCommitting) {
        badgeClass = 'bg-blue-50 border-blue-200 text-blue-600 animate-pulse shadow-md';
        dotClass = 'bg-blue-500 animate-ping';
    } else if (syncError) {
        badgeClass = 'bg-red-50 border-red-200 text-red-600 hover:bg-red-100 shadow-md';
        dotClass = 'bg-red-500 shadow-[0_0_5px_#ef4444]';
    } else if (isCloudActive) {
        badgeClass = 'bg-white border-green-200 text-green-700 hover:border-green-400 shadow-sm';
        dotClass = 'bg-green-500 shadow-[0_0_5px_#10b981]';
    }

    return (
        <>
            <div className="flex flex-row md:flex-wrap gap-1.5 mb-2 bg-white p-1.5 rounded-xl shadow-sm justify-start md:justify-between items-center relative z-[40] border border-slate-200">
                <div className="flex flex-row flex-nowrap gap-1.5 items-center flex-grow overflow-x-auto no-scrollbar">
                    {!isViewer && (
                        <Button onClick={handleSaveProject} variant="primary" icon={isCommitting ? "fas fa-sync animate-spin" : "fas fa-save"} disabled={isCommitting} size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">
                            {isCommitting ? 'Pushing...' : 'Commit'}
                        </Button>
                    )}
                    <Button onClick={() => setIsProjectListOpen(true)} variant="success" icon="fas fa-folder-open" size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">Load</Button>
                    {!isViewer && <Button onClick={resetProject} variant="warning" icon="fas fa-file" size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">New</Button>}
                    <div className="hidden md:block w-px bg-slate-200 mx-1 h-5 flex-shrink-0"></div>
                    <Button onClick={() => setView(View.TRACKER)} variant="primary" icon="fas fa-columns" size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">Tracker</Button>
                </div>

                <div className="flex items-center gap-2">
                    <div className="flex flex-col items-end">
                        <div className="flex items-center gap-1">
                            <button onClick={handleManualSync} disabled={isSyncing || isCommitting} className={`flex items-center gap-2 px-3 py-1.5 rounded-lg border text-[10px] font-black uppercase tracking-widest transition-all ${badgeClass}`}>
                                <div className={`w-1.5 h-1.5 rounded-full ${dotClass}`}></div>
                                <span className="hidden sm:inline">
                                    {isSyncing ? 'Syncing...' : syncError ? 'Re-link' : isCloudActive ? (systemMeta.connectedEmail ? `Linked: ${systemMeta.connectedEmail}` : 'Sync Data') : 'Establish Link'}
                                </span>
                            </button>
                            {driveFileUrl && (
                                <a href={driveFileUrl} target="_blank" rel="noopener noreferrer" className="p-1.5 text-slate-400 hover:text-blue-600 transition-colors" title="Locate Repository on Google Drive">
                                    <Icon name="fas fa-external-link-alt" className="text-[10px]" />
                                </a>
                            )}
                        </div>
                    </div>

                    {!isViewer && (
                        <div className="relative" ref={dbMenuRef}>
                            <button onClick={() => setIsDbMenuOpen(!isDbMenuOpen)} className={`flex items-center gap-1.5 px-3 py-1.5 text-[10px] font-black uppercase tracking-widest rounded-lg border transition-all ${isDbMenuOpen ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-700 border-slate-300'}`}>
                                <Icon name="fas fa-database" />
                            </button>
                            {isDbMenuOpen && (
                                <div className="absolute top-[calc(100%+4px)] right-0 w-64 bg-white rounded-xl shadow-2xl border border-slate-200 py-1 z-[100] animate-fade-in origin-top-right">
                                    <div className="px-3 py-2 text-[9px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 mb-1">Repositories</div>
                                    <button onClick={() => { setView(View.MANAGE_CLIENTS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold border-b border-slate-50"><Icon name="fas fa-building" className="text-indigo-600 w-4"/> Clients</button>
                                    <button onClick={() => { setView(View.MANAGE_CONTACTS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold border-b border-slate-50"><Icon name="fas fa-address-card" className="text-teal-600 w-4"/> Personnel</button>
                                    <button onClick={() => { setView(View.MANAGE_MATERIALS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold border-b border-slate-50"><Icon name="fas fa-boxes" className="text-rose-600 w-4"/> Materials</button>
                                    {isAdmin && (
                                        <>
                                            <div className="px-3 py-2 text-[9px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 mt-1 mb-1">Control</div>
                                            <button onClick={() => { setView(View.MANAGE_USERS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold"><Icon name="fas fa-user-shield" className="text-blue-700 w-4"/> Access Keys</button>
                                        </>
                                    )}
                                </div>
                            )}
                        </div>
                    )}

                    <button onClick={handleLogout} className="flex items-center justify-center w-8 h-8 rounded-lg bg-slate-900 text-slate-400 hover:bg-red-600 hover:text-white transition-all shadow-sm" title="Terminate Session">
                        <Icon name="fas fa-power-off" className="text-[10px]" />
                    </button>
                </div>
            </div>
            <ProjectListModal isOpen={isProjectListOpen} onClose={() => setIsProjectListOpen(false)} onLoadProject={handleLoadProject} projects={projects} />
        </>
    );
};

